def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_capacity in enumerate(bins):
        if bin_capacity <= 0:
            priorities[i] = float('inf')
            continue
        utilization = item / bin_capacity
        if utilization > 1:
            priorities[i] = float('inf')
            continue
        score = 0
        for j in range(1, 8):
            factor = j * utilization ** 2
            if factor < 0.2:
                score += np.exp(-factor) + np.sqrt(j)
            elif 0.2 <= factor < 0.5:
                score += np.sin(factor * np.pi) * j
            elif 0.5 <= factor < 0.8:
                score += np.tanh(factor * 2) * (j + 1)
            elif 0.8 <= factor < 1:
                score += np.log1p(factor * j) * (2 - factor)
            else:
                score += (factor ** 4) / (j ** 2 + 1)
            if j % 3 == 0:
                score *= (1 + 0.15 / (j + factor))
            if j % 4 == 0 and score > 10:
                score -= np.sqrt(score) * 0.05 * j
        if item < 0.3:
            if bin_capacity > item * 5:
                score *= 1.3
            elif bin_capacity < item * 2:
                score *= 1.2
            else:
                score += np.prod(np.tanh(np.linspace(0.1, utilization, 5)))
        elif 0.3 <= item <= 1.0:
            if bin_capacity < item * 2.5:
                score *= 1.5
            elif bin_capacity > item * 7:
                score *= 0.6
            else:
                for k in range(1, 6):
                    score += np.log1p(k * utilization) * np.cos(k)
        else:
            max_k = int(bin_capacity // item)
            if max_k == 0:
                max_k = 1
            for k in range(1, max_k + 3):
                increment = np.sin(k + utilization) + np.log(k * utilization + 2)
                if increment > 1:
                    score += increment * 0.7
                else:
                    score += increment ** 1.5
                if k % 2 == 0 and score > 20:
                    score *= 0.95
            if bin_capacity < item * 4:
                score *= 1.4
            elif bin_capacity > item * 10:
                score *= 0.8
            else:
                score += np.sum(np.sqrt(np.arange(1, 4) * utilization))
        if score < 0:
            score = abs(score) + 2
        if score > 50:
            score = 50 + np.log(score - 49)
        priorities[i] = score
    return priorities
